oxy_webhelp_navlinks = {"azr_devops-d26997e31624":{"topics":[{"title":"Introduction to Azure DevOps","href":"azure_devops\/azr_devops_protection_key_features.html","menu":{"hasChildren":false},"tocID":"tocId-d26997e31637","next":"tocId-d26997e31637"},{"title":"High-level implementation workflow for Azure DevOps","shortdesc":"<p class=\"shortdesc\">The Azure DevOps protection implementation workflow involves a structured approach to         secure data management, starting with planning and preparation, followed by Azure DevOps         organization setup, Azure DevOps protection, continuous management and optimization, and         repository recovery.<\/p>","href":"azure_devops\/azr_devops_high_level_implement_workflow.html","attributes":{"data-id":"azr_devops_high_level_implement_workflow"},"menu":{"hasChildren":false},"tocID":"azr_devops_high_level_implement_workflow-d26997e31699","topics":[]},{"title":"Quick links for Azure DevOps","shortdesc":"<p class=\"shortdesc\">Immediate access to important tasks and information, enabling quick setup, daily         operations, and critical recovery.<\/p>","href":"azure_devops\/azr_devops_quick_links.html","attributes":{"data-id":"azr_devops_quick_links"},"menu":{"hasChildren":false},"tocID":"azr_devops_quick_links-d26997e31710","topics":[]},{"title":"Plan your Azure DevOps protection","shortdesc":"<p class=\"shortdesc\">Before setting up an Azure DevOps organization in <span class=\"ph\">RSC<\/span>, you are         required to plan the user and access management for designated <span class=\"ph\">RSC<\/span> users.         This planning also involves reviewing the permissions that <span class=\"ph\">RSC<\/span> requires in         your Azure environment to protect your Azure DevOps organizations.<\/p>","href":"azure_devops\/azr_devops_plan_protection.html","attributes":{"data-id":"azr_devops_plan_protection"},"menu":{"hasChildren":false},"tocID":"azr_devops_plan_protection-d26997e31721","next":"azr_devops_plan_protection-d26997e31721"},{"title":"Add Azure DevOps organization to <span class=\"ph\">RSC<\/span>","shortdesc":"<p class=\"shortdesc\">You can add Azure DevOps organization in <span class=\"ph\">RSC<\/span> to start protecting         Azure DevOps resources.<\/p>","href":"azure_devops\/azr_devops_add_orgs.html","attributes":{"data-id":"azr_devops_add_orgs"},"menu":{"hasChildren":false},"tocID":"azr_devops_add_orgs-d26997e31801","next":"azr_devops_add_orgs-d26997e31801"},{"title":"Set up protection for Azure DevOps","shortdesc":"<p class=\"shortdesc\">You can set up SLA Domains to apply data protection policies, ensuring automatic and         hierarchical protection of Azure DevOps organizations, projects, and repositories, with         granular control overriding higher-level assignments.<\/p>","href":"azure_devops\/azr_devops_set_up_protection.html","attributes":{"data-id":"azr_devops_set_up_protection"},"menu":{"hasChildren":false},"tocID":"azr_devops_set_up_protection-d26997e32024","next":"azr_devops_set_up_protection-d26997e32024"},{"title":"Manage Azure DevOps organizations","shortdesc":"<p class=\"shortdesc\">After completing the protection setup for Azure DevOps organizations, projects, and         repos, <span class=\"ph\">RSC<\/span> takes automated snapshots of those repos based on the configured         policies in SLA Domains. You can also take on-demand snapshots and refresh Azure DevOps         organizations for better resource management.<\/p>","href":"azure_devops\/azr_devops_manage_organizations.html","attributes":{"data-id":"azr_devops_manage_organizations"},"menu":{"hasChildren":false},"tocID":"azr_devops_manage_organizations-d26997e32139","next":"azr_devops_manage_organizations-d26997e32139"},{"title":"Recover Azure DevOps","shortdesc":"<p class=\"shortdesc\">After <span class=\"ph\">RSC<\/span> takes snapshots of your Azure DevOps repositories, you can         recover the necessary details.<\/p>","href":"azure_devops\/azr_devops_recover.html","attributes":{"data-id":"azr_devops_recover"},"menu":{"hasChildren":false},"tocID":"azr_devops_recover-d26997e32213","next":"azr_devops_recover-d26997e32213"},{"title":"Access Azure DevOps reports","shortdesc":"<p class=\"shortdesc\">With <span class=\"ph\">RSC<\/span>, you can create and download reports based on templates to         monitor the protection status of your Azure DevOps organizations, projects, and         repositories.<\/p>","href":"azure_devops\/azr_devops_access_reports.html","attributes":{"data-id":"azr_devops_access_reports"},"menu":{"hasChildren":false},"tocID":"azr_devops_access_reports-d26997e32251","next":"azr_devops_access_reports-d26997e32251"}]}};